import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import LoginModal from './LoginModal';
import logoWhiteImage from '../assets/images/logo1.png';

const Header = ({ onLoginClick }) => {
    const { t, i18n } = useTranslation();
    const [menuOpen, setMenuOpen] = useState(false);
    const [scrolled, setScrolled] = useState(false);
    const [dropdownOpen, setDropdownOpen] = useState('');
    const [isLoginModalOpen, setIsLoginModalOpen] = useState(false);
    const [hoveredItem, setHoveredItem] = useState(null);

    const location = useLocation();

    useEffect(() => {
        setMenuOpen(false);
        setDropdownOpen('');
    }, [location]);

    useEffect(() => {
        const handleScroll = () => {
            const isScrolled = window.scrollY > 50;
            if (isScrolled !== scrolled) {
                setScrolled(isScrolled);
            }
        };

        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, [scrolled]);

    const toggleMenu = () => setMenuOpen(!menuOpen);
    const toggleLanguage = () => {
        const newLanguage = i18n.language === 'en' ? 'ja' : 'en';
        i18n.changeLanguage(newLanguage);
    };
    const toggleDropdown = (menu) => setDropdownOpen(dropdownOpen === menu ? '' : menu);
    const handleMouseEnter = (item) => {
        setHoveredItem(item);
        if (item === 'courses' || item === 'about') setDropdownOpen(item);
    };
    const handleMouseLeave = () => {
        setHoveredItem(null);
        setDropdownOpen('');
    };
    const openModal = () => {
        setIsLoginModalOpen(true);
        if (menuOpen) setMenuOpen(false);
    };
    const closeModal = () => setIsLoginModalOpen(false);
    const isActiveLink = (path) => location.pathname === path || location.pathname.startsWith(path + '/');
    const getCurrentLanguage = () => i18n.language === 'en' ? 'EN' : 'JP';

    return (
        <>
            {/* 🎨 Glassmorphism Header with Dynamic Background */}
            <header className={`fixed top-0 left-0 right-0 z-50 transition-all duration-700 ease-out ${
                scrolled 
                    ? 'bg-white/10 backdrop-blur-3xl shadow-2xl border-b border-white/20' 
                    : 'bg-transparent'
            }`}>
                {/* Animated Gradient Background */}
                <div className="absolute inset-0 bg-gradient-to-br from-slate-900/95 via-blue-900/90 to-purple-900/85 backdrop-blur-2xl">
                    {/* Floating Particles Effect */}
                    <div className="absolute inset-0 overflow-hidden">
                        <div className="absolute -top-4 -left-4 w-72 h-72 bg-blue-500/10 rounded-full mix-blend-multiply filter blur-xl animate-pulse"></div>
                        <div className="absolute -top-4 -right-4 w-72 h-72 bg-purple-500/10 rounded-full mix-blend-multiply filter blur-xl animate-pulse animation-delay-2000"></div>
                        <div className="absolute -bottom-8 left-20 w-72 h-72 bg-pink-500/10 rounded-full mix-blend-multiply filter blur-xl animate-pulse animation-delay-4000"></div>
                    </div>

                    {/* Dot Pattern Overlay */}
                    <div className="absolute inset-0 opacity-30" style={{
                        backgroundImage: `radial-gradient(circle at 20px 20px, rgba(255,255,255,0.15) 1px, transparent 0)`,
                        backgroundSize: '40px 40px'
                    }}></div>
                </div>

                <div className="relative container mx-auto px-6 lg:px-8">
                    <div className="flex items-center justify-between h-24">
                        {/* ✨ Logo with Magnetic Hover & Shine Effect */}
                        <Link to="/" className="group relative z-10">
                            <div className="flex items-center space-x-4">
                                <div className="relative">
                                    {/* Magnetic Glow Effect */}
                                    <div className="absolute -inset-6 bg-gradient-to-r from-cyan-400/30 via-blue-500/30 to-purple-600/30 rounded-3xl blur-2xl opacity-0 group-hover:opacity-100 transition-all duration-700 animate-pulse group-hover:animate-none"></div>

                                    {/* Logo Container with 3D Transform */}
                                    <div className="relative bg-gradient-to-br from-cyan-400 via-blue-500 to-purple-600 p-4 rounded-2xl transform group-hover:scale-110 group-hover:rotate-6 transition-all duration-500 shadow-2xl group-hover:shadow-cyan-500/25 overflow-hidden">
                                        <img 
                                            src={logoWhiteImage} 
                                            alt="Forum Information Academy" 
                                            className="h-12 w-auto filter brightness-0 invert transition-all duration-500 group-hover:scale-110 relative z-10" 
                                        />

                                        {/* Shine Sweep Effect */}
                                        <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/40 to-transparent -skew-x-12 translate-x-[-200%] group-hover:translate-x-[200%] transition-transform duration-1200 ease-out"></div>

                                        {/* Pulsing Ring */}
                                        <div className="absolute inset-0 rounded-2xl ring-2 ring-white/20 group-hover:ring-white/40 transition-all duration-500"></div>
                                    </div>
                                </div>

                                <div className="hidden md:block">
                                    <div className="text-2xl font-black bg-gradient-to-r from-cyan-300 via-blue-300 to-purple-300 bg-clip-text text-transparent group-hover:from-purple-300 group-hover:via-pink-300 group-hover:to-cyan-300 transition-all duration-700 transform group-hover:scale-105">
                                        Forum Academy
