                                                            { to: '/courses/data-science', gradient: 'from-blue-500 to-purple-600', icon: '📊', title: t('courses.dataScience') || 'Data Science', desc: t('courses.dataScienceDesc') || 'Analytics & ML' },
                                                            { to: '/courses/cybersecurity', gradient: 'from-purple-500 to-pink-600', icon: '🔒', title: t('courses.cybersecurity') || 'Cybersecurity', desc: t('courses.cybersecurityDesc') || 'Security expertise' },
                                                            { to: '/courses/ai-ml', gradient: 'from-pink-500 to-red-600', icon: '🤖', title: t('courses.aiMl') || 'AI & ML', desc: t('courses.aiMlDesc') || 'Artificial Intelligence' }
