                                                            >
                                                                <div className={`w-10 h-10 bg-gradient-to-br ${item.gradient} rounded-xl flex items-center justify-center group-hover:scale-110 transition-transform duration-300`}>
                                                                    <span className="text-white">{item.icon}</span>
                                                                </div>
                                                                <span className="font-medium text-white group-hover:text-cyan-200 transition-colors duration-300">{item.title}</span>
                                                            </Link>
                                                        ))}
                                                    </div>
                                                </div>

                                                {/* Call to Action */}
                                                <div className="bg-gradient-to-br from-slate-800/80 via-blue-900/80 to-purple-900/80 rounded-2xl p-6 text-white relative overflow-hidden border border-white/20">
                                                    <div className="absolute inset-0 bg-gradient-to-r from-cyan-500/10 to-purple-500/10"></div>

                                                    <div className="relative">
                                                        <h3 className="text-xl font-bold mb-3 flex items-center">
                                                            <span className="text-3xl mr-3">🎯</span>
                                                            Start Your Journey
                                                        </h3>
                                                        <p className="text-blue-200 mb-4 text-sm leading-relaxed">Join thousands of students already transforming their careers with our innovative programs.</p>
                                                        <Link 
                                                            to="/apply" 
                                                            className="inline-flex items-center px-6 py-3 bg-gradient-to-r from-cyan-500 to-blue-600 hover:from-blue-600 hover:to-purple-600 text-white rounded-xl font-semibold transform hover:scale-105 transition-all duration-300 group shadow-lg hover:shadow-xl"
                                                        >
                                                            Apply Now
                                                            <svg className="w-5 h-5 ml-2 group-hover:translate-x-1 transition-transform duration-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" />
                                                            </svg>
                                                        </Link>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            {/* About Dropdown with Enhanced Effects */}
                            <div 
                                className="relative group"
                                onMouseEnter={() => handleMouseEnter('about')}
                                onMouseLeave={handleMouseLeave}
                            >
                                <button className={`relative px-6 py-3 rounded-2xl font-semibold transition-all duration-500 overflow-hidden group/btn ${
                                    scrolled 
                                        ? 'text-slate-200 hover:text-white' 
                                        : 'text-white hover:text-purple-200'
                                } ${isActiveLink('/about') ? 'bg-gradient-to-r from-purple-500 to-pink-600 text-white shadow-lg shadow-purple-500/25' : ''}`}>

                                    <div className="absolute inset-0 bg-gradient-to-r from-purple-500 via-pink-600 to-red-500 opacity-0 group-hover/btn:opacity-100 transition-all duration-500 transform scale-x-0 group-hover/btn:scale-x-100 origin-left"></div>
                                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -skew-x-12 translate-x-[-100%] group-hover/btn:translate-x-[200%] transition-transform duration-1000"></div>

                                    <div className="relative flex items-center space-x-2">
                                        <span className="relative z-10">{t('navigation.about')}</span>
                                        <svg className={`w-5 h-5 transition-all duration-500 relative z-10 ${dropdownOpen === 'about' ? 'rotate-180 text-purple-300' : ''} group-hover/btn:scale-110`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                                        </svg>
                                    </div>
                                </button>

                                <div className={`absolute top-full left-1/2 transform -translate-x-1/2 mt-6 w-96 transition-all duration-700 ${
                                    dropdownOpen === 'about' 
                                        ? 'opacity-100 translate-y-0 scale-100' 
                                        : 'opacity-0 translate-y-8 scale-95 pointer-events-none'
                                }`}>
                                    <div className="bg-white/10 backdrop-blur-3xl rounded-2xl shadow-2xl border border-white/20 overflow-hidden">
                                        <div className="h-1 bg-gradient-to-r from-purple-400 via-pink-500 to-red-500"></div>

                                        <div className="p-6 space-y-2">
                                            {[
                                                { to: '/about', gradient: 'from-blue-500 to-purple-600', icon: 'ℹ️', title: t('navigation.aboutUs') || 'About Us' },
                                                { to: '/team', gradient: 'from-purple-500 to-pink-600', icon: '👥', title: t('navigation.ourTeam') || 'Our Team' },
                                                { to: '/partners', gradient: 'from-pink-500 to-red-600', icon: '🤝', title: t('navigation.industryPartners') || 'Industry Partners' },
                                                { to: '/testimonials', gradient: 'from-yellow-500 to-orange-600', icon: '⭐', title: t('navigation.studentSuccess') || 'Student Success' }
                                            ].map((item, index) => (
                                                <Link 
                                                    key={index}
                                                    to={item.to} 
                                                    className="group flex items-center space-x-4 p-4 rounded-xl hover:shadow-lg transition-all duration-300 transform hover:-translate-y-1 border border-transparent hover:border-white/20 hover:bg-white/10"
                                                >
                                                    <div className={`w-12 h-12 bg-gradient-to-br ${item.gradient} rounded-xl flex items-center justify-center group-hover:scale-110 group-hover:rotate-6 transition-all duration-300 shadow-lg`}>
                                                        <span className="text-white text-lg">{item.icon}</span>
                                                    </div>
                                                    <span className="font-medium text-white group-hover:text-cyan-200 transition-colors duration-300">{item.title}</span>
                                                </Link>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                            </div>

                            {/* Other Navigation Items with Gradient Effects */}
                            {[
                                { to: '/news', title: t('navigation.newsEvents') || 'News & Events', gradient: 'from-green-500 to-emerald-600' },
                                { to: '/career-services', title: t('navigation.careerServices') || 'Career Services', gradient: 'from-indigo-500 to-purple-600' },
                                { to: '/contact', title: t('navigation.contact') || 'Contact', gradient: 'from-orange-500 to-red-600' }
                            ].map((item, index) => (
                                <Link 
                                    key={index}
                                    to={item.to} 
                                    className={`relative px-6 py-3 rounded-2xl font-semibold transition-all duration-500 overflow-hidden group ${
                                        scrolled 
                                            ? 'text-slate-200 hover:text-white' 
                                            : 'text-white hover:text-cyan-200'
                                    } ${isActiveLink(item.to) ? `bg-gradient-to-r ${item.gradient} text-white shadow-lg` : ''}`}
                                >
                                    <div className={`absolute inset-0 bg-gradient-to-r ${item.gradient} opacity-0 group-hover:opacity-100 transition-all duration-500 transform scale-x-0 group-hover:scale-x-100 origin-left`}></div>
                                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -skew-x-12 translate-x-[-100%] group-hover:translate-x-[200%] transition-transform duration-1000"></div>
                                    <span className="relative z-10">{item.title}</span>
                                </Link>
                            ))}
                        </nav>

                        {/* 🎨 Enhanced Action Buttons */}
                        <div className="flex items-center space-x-4">
                            {/* Language Selector with Magnetic Effect */}
                            <button 
                                onClick={toggleLanguage}
                                className={`hidden md:flex items-center space-x-3 px-5 py-3 rounded-2xl font-medium transition-all duration-500 group relative overflow-hidden border ${
                                    scrolled ? 'text-slate-200 hover:text-white border-white/20 hover:border-white/40' : 'text-white border-white/30 hover:border-white/60'
                                }`}
                            >
                                <div className="absolute inset-0 bg-gradient-to-r from-cyan-500 to-blue-600 opacity-0 group-hover:opacity-100 transition-all duration-500 transform scale-x-0 group-hover:scale-x-100 origin-left"></div>

                                <svg className="relative w-6 h-6 group-hover:scale-110 group-hover:rotate-12 transition-all duration-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 5h12M9 3v2m1.048 9.5A18.022 18.022 0 016.412 9m6.088 9h7M11 21l5-10 5 10M12.751 5C11.783 10.77 8.07 15.61 3 18.129" />
                                </svg>
                                <span className="relative font-bold">{getCurrentLanguage()}</span>
                            </button>

                            {/* Login Button with Enhanced Effects */}
                            <button 
                                onClick={onLoginClick}
                                className={`hidden md:flex items-center space-x-3 px-6 py-3 rounded-2xl font-semibold transition-all duration-500 group relative overflow-hidden border ${
                                    scrolled 
                                        ? 'text-slate-200 hover:text-white border-white/20 hover:border-white/40' 
                                        : 'text-white border-white/30 hover:border-white/60'
                                }`}
                            >
                                <div className="absolute inset-0 bg-gradient-to-r from-purple-500 to-pink-600 opacity-0 group-hover:opacity-100 transition-all duration-500 transform scale-x-0 group-hover:scale-x-100 origin-left"></div>

                                <svg className="relative w-6 h-6 group-hover:scale-110 transition-all duration-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                                </svg>
                                <span className="relative">{t('buttons.login') || 'Login'}</span>
                            </button>

                            {/* ✨ Enhanced Apply Button with Multiple Effects */}
                            <Link 
                                to="/apply" 
                                className="relative bg-gradient-to-r from-cyan-500 via-blue-600 to-purple-600 hover:from-purple-600 hover:via-pink-600 hover:to-red-600 text-white px-8 py-3 rounded-2xl font-bold transition-all duration-700 transform hover:scale-110 hover:shadow-2xl hover:shadow-cyan-500/25 flex items-center space-x-3 group overflow-hidden"
                            >
                                {/* Multiple Shine Effects */}
                                <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/30 to-transparent -skew-x-12 translate-x-[-100%] group-hover:translate-x-[200%] transition-transform duration-1000 ease-out"></div>
                                <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent skew-x-12 translate-x-[100%] group-hover:translate-x-[-200%] transition-transform duration-1200 ease-out delay-200"></div>

                                {/* Pulsing Background */}
                                <div className="absolute inset-0 bg-gradient-to-r from-cyan-400 to-purple-600 opacity-0 group-hover:opacity-30 transition-opacity duration-500 animate-pulse"></div>

                                <span className="relative font-black">{t('buttons.applyNow') || 'Apply Now'}</span>
                                <svg className="relative w-6 h-6 group-hover:translate-x-2 group-hover:scale-110 transition-all duration-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" />
                                </svg>
                            </Link>

                            {/* 📱 Enhanced Mobile Menu Button */}
                            <button 
                                onClick={toggleMenu}
                                className={`lg:hidden flex flex-col items-center justify-center w-14 h-14 rounded-2xl transition-all duration-300 group relative overflow-hidden border border-white/30 ${
                                    scrolled ? 'text-slate-200 hover:bg-white/10' : 'text-white hover:bg-white/10'
                                }`}
                            >
                                <div className={`absolute inset-0 bg-gradient-to-r from-red-500 to-pink-600 opacity-0 transition-opacity duration-300 ${menuOpen ? 'opacity-100' : 'group-hover:opacity-20'}`}></div>

                                <span className={`relative w-7 h-0.5 bg-current transition-all duration-500 ${menuOpen ? 'rotate-45 translate-y-2 bg-white' : ''}`}></span>
                                <span className={`relative w-7 h-0.5 bg-current mt-2 transition-all duration-500 ${menuOpen ? 'opacity-0' : ''}`}></span>
                                <span className={`relative w-7 h-0.5 bg-current mt-2 transition-all duration-500 ${menuOpen ? '-rotate-45 -translate-y-2 bg-white' : ''}`}></span>
                            </button>
                        </div>
                    </div>

                    {/* 📱 Enhanced Mobile Menu */}
                    <div className={`lg:hidden transition-all duration-700 overflow-hidden ${
                        menuOpen ? 'max-h-screen opacity-100 pb-8' : 'max-h-0 opacity-0'
                    }`}>
                        <div className="space-y-4 pt-6 border-t border-white/20">
                            {[
                                { to: '/courses', title: t('navigation.programs') || 'Programs', icon: '🎓', gradient: 'from-cyan-500 to-blue-600' },
                                { to: '/about', title: t('navigation.about') || 'About', icon: 'ℹ️', gradient: 'from-blue-500 to-purple-600' },
                                { to: '/news', title: t('navigation.newsEvents') || 'News & Events', icon: '📰', gradient: 'from-purple-500 to-pink-600' },
                                { to: '/career-services', title: t('navigation.careerServices') || 'Career Services', icon: '💼', gradient: 'from-pink-500 to-red-600' },
                                { to: '/contact', title: t('navigation.contact') || 'Contact', icon: '📞', gradient: 'from-green-500 to-blue-600' }
                            ].map((item, index) => (
                                <Link 
                                    key={index}
                                    to={item.to} 
                                    className="flex items-center space-x-4 py-4 px-6 rounded-2xl text-white hover:bg-white/10 transition-all duration-300 group transform hover:translate-x-2"
                                >
                                    <div className={`w-12 h-12 bg-gradient-to-br ${item.gradient} rounded-xl flex items-center justify-center group-hover:scale-110 transition-transform duration-300`}>
                                        <span className="text-xl">{item.icon}</span>
                                    </div>
                                    <span className="font-semibold text-lg">{item.title}</span>
                                </Link>
                            ))}

                            <div className="pt-6 space-y-4 border-t border-white/20">
                                <button 
                                    onClick={toggleLanguage}
                                    className="flex items-center space-x-4 w-full py-4 px-6 rounded-2xl text-white hover:bg-white/10 transition-all duration-300 group"
                                >
                                    <div className="w-12 h-12 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl flex items-center justify-center group-hover:scale-110 transition-transform duration-300">
                                        <span className="text-xl">🌐</span>
                                    </div>
                                    <span className="font-semibold text-lg">{getCurrentLanguage()} - Switch Language</span>
                                </button>

                                <button 
                                    onClick={onLoginClick}
                                    className="flex items-center space-x-4 w-full py-4 px-6 rounded-2xl text-white hover:bg-white/10 transition-all duration-300 group"
                                >
                                    <div className="w-12 h-12 bg-gradient-to-br from-purple-500 to-pink-600 rounded-xl flex items-center justify-center group-hover:scale-110 transition-transform duration-300">
                                        <span className="text-xl">👤</span>
                                    </div>
                                    <span className="font-semibold text-lg">{t('buttons.login') || 'Login'}</span>
                                </button>

                                <Link 
                                    to="/apply" 
                                    className="block py-5 bg-gradient-to-r from-cyan-500 to-purple-600 hover:from-purple-600 hover:to-pink-600 text-white text-center rounded-2xl font-bold text-lg transform hover:scale-105 transition-all duration-300 shadow-lg hover:shadow-2xl"
                                >
                                    {t('buttons.applyNow') || 'Apply Now'}
                                </Link>
                            </div>
                        </div>
                    </div>
                </div>
            </header>

            <LoginModal 
                isOpen={isLoginModalOpen} 
                onClose={closeModal} 
            />
        </>
    );
};

export default Header;
